package com.restaurantcraft.util; import com.restaurantcraft.blockentity.*; import com.restaurantcraft.entity.CustomerEntity; import com.restaurantcraft.data.RestaurantLevel; import net.minecraft.core.BlockPos; import net.minecraft.server.level.ServerLevel; import net.minecraft.world.level.Level; import net.minecraft.world.phys.AABB; public class RestaurantCustomerUtil { public static BlockPos findSpawn(ServerLevel l, BlockPos entrance){for(BlockPos p:BlockPos.betweenClosed(entrance.offset(-2,0,-2),entrance.offset(2,2,2))) if(l.getBlockState(p).isAir()&&l.getBlockState(p.below()).isSolid())return p.immutable(); return entrance.above();} public static BlockPos findFreeChair(Level l, BlockPos restaurant){ if(!(l.getBlockEntity(restaurant) instanceof RestaurantManagementBlockEntity be))return null; var r=RestaurantAreaUtil.scan(l,be.level(),restaurant); for(BlockPos p:BlockPos.betweenClosed(r.min(),r.max())) if(l.getBlockEntity(p) instanceof RestaurantChairBlockEntity c&&!c.isOccupied())return p.immutable(); return null;} public static void removeCustomers(Level l, BlockPos restaurant){ if(l instanceof ServerLevel sl) for(CustomerEntity c:sl.getEntitiesOfClass(CustomerEntity.class,new AABB(restaurant).inflate(96),e->restaurant.equals(e.restaurantPos()))) c.discard();} }
